+    fn escape_hash(&mut self, byte: u8) {
+        if byte == b'8' {
+            // DECALN: fill entire screen with 'E', reset scroll region, cursor to origin.
+            for cell in self.grid.iter_mut() {
+                *cell = VCell {
+                    ch: 'E',
+                    style: CellStyle::default(),
+                };
+            }
